INSERT INTO `general_knowledge_questions` VALUES (1,'¿Cuál es la capital de Francia?','Londres','París','Madrid','Roma',1,1,'2025-11-26 14:17:13.468245','2025-11-26 14:17:13.468245'),(2,'¿En qué año llegó el hombre a la Luna?','1965','1969','1972','1975',1,1,'2025-11-26 14:17:13.473535','2025-11-26 14:17:13.473535'),(3,'¿Cuál es el océano más grande del mundo?','Atlántico','Índico','Pacífico','Ártico',2,1,'2025-11-26 14:17:13.479535','2025-11-26 14:17:13.479535'),(4,'¿Quién pintó la Mona Lisa?','Picasso','Van Gogh','Leonardo da Vinci','Miguel Ángel',2,1,'2025-11-26 14:17:13.484767','2025-11-26 14:17:13.484767'),(5,'¿Cuál es el planeta más cercano al Sol?','Venus','Tierra','Mercurio','Marte',2,1,'2025-11-26 14:17:13.488731','2025-11-26 14:17:13.488731'),(6,'¿Cuántos continentes hay en el mundo?','5','6','7','8',2,1,'2025-11-26 14:17:13.492941','2025-11-26 14:17:13.492941'),(7,'¿Cuál es el río más largo del mundo?','Amazonas','Nilo','Misisipi','Yangtsé',0,1,'2025-11-26 14:17:13.497941','2025-11-26 14:17:13.497941'),(8,'¿En qué continente está Egipto?','Asia','Europa','África','América',2,1,'2025-11-26 14:17:13.503150','2025-11-26 14:17:13.503150'),(9,'¿Cuál es la montaña más alta del mundo?','K2','Kilimanjaro','Everest','Aconcagua',2,1,'2025-11-26 14:17:13.507150','2025-11-26 14:17:13.507150'),(10,'¿Quién escribió \'Don Quijote de la Mancha\'?','Gabriel García Márquez','Miguel de Cervantes','Pablo Neruda','Mario Vargas Llosa',1,1,'2025-11-26 14:17:13.512328','2025-11-26 14:17:13.512328'),(11,'¿Cuál es el elemento químico más abundante en el universo?','Oxígeno','Hidrógeno','Helio','Carbono',1,1,'2025-11-26 14:17:13.516369','2025-11-26 14:17:13.516369'),(12,'¿En qué año comenzó la Segunda Guerra Mundial?','1937','1939','1941','1943',1,1,'2025-11-26 14:17:13.521334','2025-11-26 14:17:13.521334'),(13,'¿Cuál es el país más grande del mundo?','China','Estados Unidos','Rusia','Canadá',2,1,'2025-11-26 14:17:13.525598','2025-11-26 14:17:13.525598'),(14,'¿Qué instrumento tocab